# --- Security: Validate and sanitize plugin code ---
sub validate_plugin_code {
    my ($code, $filename) = @_;

    # Check for obviously dangerous operations
    my @forbidden_patterns = (
        qr/\bsystem\s*\(/,
        qr/\bexec\s*\(/,
        qr/\b`[^`]*`/,
        qr/\bqx\s*[\{\(\[\/]/,
        qr/\bunlink\s*\(/,
        qr/\brmdir\s*\(/,
        qr/\brename\s*\(/,
        qr/\bchmod\s*\(/,
        qr/\bchown\s*\(/,
        qr/\bkill\s*\(/,
        qr/\bfork\s*\(/,
        qr/\bsocket\s*\(/,
        qr/\bconnect\s*\(/,
        qr/\bbind\s*\(/,
        qr/\blisten\s*\(/,
        qr/\baccept\s*\(/,
        qr/\brequire\s+/,
        qr/\buse\s+/,
        qr/\bdo\s+['"][^'"]+['"]/,
        qr/\bBEGIN\s*\{/,
        qr/\bEND\s*\{/,
        qr/\bINIT\s*\{/,
        qr/\bCHECK\s*\{/,
        qr/\bUNITCHECK\s*\{/,
        qr/\beval\s*\(/,           # No nested eval
        qr/\beval\s*\{/,           # No nested eval blocks
        qr/\bopen\s*\(/,
        qr/\bsymlink\s*\(/,
        qr/\bglob\s*\(/,
        qr/\breaddir\s*\(/,
        qr/\bopendir\s*\(/,
        qr/\bDBI\b/,
        qr/\bIO::/,
        qr/\bFile::(?!Spec|Basename)/,
        qr/\bENV\b/,
        qr/\$ENV\b/,
        qr/\@ENV\b/,
        qr/%ENV\b/,
    );

    for my $pattern (@forbidden_patterns) {
        if ($code =~ $pattern) {
            log_error("Plugin '$filename' contains forbidden pattern: $pattern");
            return 0;
        }
    }

    return 1;
}

# --- Load a single plugin configuration file ---
sub load_plugin_file {
    my ($filepath) = @_;

    my $filename = basename($filepath);

    # Validate file path - ensure it's within the plugin directory
    my $abs_plugin_dir = File::Spec->rel2abs($PLUGIN_DIR);
    my $abs_filepath   = File::Spec->rel2abs($filepath);

    unless ($abs_filepath =~ /^\Q$abs_plugin_dir\E/) {
        log_error("Plugin file '$filepath' is outside the allowed plugin directory.");
        return undef;
    }

    unless (-f $filepath && -r $filepath) {
        log_error("Plugin file '$filepath' does not exist or is not readable.");
        return undef;
    }

    my $file_size = -s $filepath;
    if ($file_size > $MAX_PLUGIN_SIZE) {
        log_error("Plugin file '$filepath' exceeds maximum allowed size ($MAX_PLUGIN_SIZE bytes).");
        return undef;
    }

    # Read the plugin configuration file
    open my $fh, '<', $filepath or do {
        log_error("Cannot open plugin file '$filepath': $!");
        return undef;
    };

    my %plugin_meta;
    my $code_section = 0;
    my $plugin_code  = '';

    while (my $line = <$fh>) {
        chomp $line;

        # Parse metadata headers (key: value format before __CODE__ marker)
        if (!$code_section) {
            if ($line =~ /^__CODE__\s*$/) {
                $code_section = 1;
                next;
            }
            if ($line =~ /^\s*#/) { next; }  # Skip comments
            if ($line =~ /^\s*$/) { next; }  # Skip blank lines
            if ($line =~ /^(\w+)\s*:\s*(.+)$/) {
                $plugin_meta{lc($1)} = $2;
            }
        } else {
            $plugin_code .= $line . "\n";
        }
    }
    close $fh;

    unless ($plugin_meta{name}) {
        log_error("Plugin file '$filepath' is missing required 'name' metadata.");
        return undef;
    }

    unless ($plugin_meta{version}) {
        $plugin_meta{version} = '0.0.1';
    }

    unless ($code_section && length($plugin_code) > 0) {
        log_error("Plugin '$plugin_meta{name}' has no code section (__CODE__ marker missing or empty).");
        return undef;
    }

    return {
        filepath => $filepath,
        metadata => \%plugin_meta,
        code     => $plugin_code,
    };
}

# --- Execute plugin code safely using eval ---
sub execute_plugin {
    my ($plugin, $context) = @_;

    my $name    = $plugin->{metadata}{name};
    my $version = $plugin->{metadata}{version};
    my $code    = $plugin->{code};

    log_info("Executing plugin: '$name' v$version");

    # Validate the code before execution
    unless (validate_plugin_code($code, $name)) {
        log_error("Plugin '$name' failed security validation. Skipping execution.");
        return { success => 0, error => "Security validation failed" };
    }

    # Wrap plugin code in a restricted scope
    # The plugin receives $context as a hashref for input/output
    my $wrapped_code = qq{
        package Plugin::Sandbox::$name;
        no strict 'refs';
        sub {
            my (\$ctx) = \@_;
            $code
        }
    };

    # Compile the plugin code
    my $plugin_sub = eval($wrapped_code);

    if ($@) {
        log_error("Plugin '$name' compilation error: $@");
        return { success => 0, error => "Compilation error: $@" };
    }

    unless (ref($plugin_sub) eq 'CODE') {
        log_error("Plugin '$name' did not compile to a code reference.");
        return { success => 0, error => "Invalid plugin structure" };
    }

    # Execute with timeout protection
    my $result;
    my $timeout = $plugin->{metadata}{timeout} || 5;

    eval {
        local $SIG{ALRM} = sub { die "Plugin execution timed out after ${timeout}s\n" };
        alarm($timeout);

        $result = $plugin_sub->($context);

        alarm(0);
    };

    if ($@) {
        alarm(0);  # Ensure alarm is cleared
        log_error("Plugin '$name' runtime error: $@");
        return { success => 0, error => "Runtime error: $@" };
    }

    log_info("Plugin '$name' executed successfully.");
    return { success => 1, result => $result };
}

# --- Discover and load all plugins from the plugin directory ---
sub discover_plugins {
    my ($dir) = @_;

    unless (-d $dir) {
        log_warn("Plugin directory '$dir' does not exist. Creating it.");
        mkdir $dir or do {
            log_error("Cannot create plugin directory '$dir': $!");
            return ();
        };
    }

    opendir my $dh, $dir or do {
        log_error("Cannot open plugin directory '$dir': $!");
        return ();
    };

    my @plugin_files = grep { $_ =~ $ALLOWED_EXTENSIONS } readdir($dh);
    closedir $dh;

    my @plugins;
    for my $file (sort @plugin_files) {
        my $filepath = File::Spec->catfile($dir, $file);
        log_info("Loading plugin file: $filepath");

        my $plugin = load_plugin_file($filepath);
        if ($plugin) {
            push @plugins, $plugin;
            log_info("Loaded plugin: '$plugin->{metadata}{name}' v$plugin->{metadata}{version}");
        }
    }

    return @plugins;
}

