sub write_file {
    my ($path, $content) = @_;
    open my $fh, '>', $path or die "Cannot write '$path': $!";
    print $fh $content;
    close $fh;
}

# --- Pretty print results ---
sub print_result {
    my ($label, $data, $indent) = @_;
    $indent //= 0;
    my $pad = "  " x $indent;

    if (ref $data eq 'HASH') {
        print "${pad}${label}:\n" if $label;
        for my $key (sort keys %$data) {
            print_result($key, $data->{$key}, $indent + 1);
        }
    } elsif (ref $data eq 'ARRAY') {
        print "${pad}${label}: [" . join(", ", map { defined $_ ? $_ : 'undef' } @$data) . "]\n";
    } else {
        $data //= 'undef';
        if ($label) {
            print "${pad}${label}: $data\n";
        } else {
            print "${pad}$data\n";
        }
    }
}

